#!/usr/bin/env bash
# gen-c-abi.sh — generate the Vokra C ABI header with cbindgen (M0-09-T10).
#
# Ticket: M0-09-T10. Basis: FR-TL-04 (build script `gen-c-abi.sh`), IF-01
# (single public header `include/vokra.h`). The header is committed so C
# consumers can grab it straight from the repo; CI regenerates it on every PR
# and fails on drift (`--check`), which is how WP M0-09's "vokra.h is
# generated by cbindgen in CI" condition is met.
#
# cbindgen is a build-only tool (MPL-2.0); it is NOT a workspace dependency and
# never ships in an artifact (ADR-0003, docs/license-audit.md).
#
# Usage:
#   scripts/gen-c-abi.sh            # (re)generate include/vokra.h in place
#   scripts/gen-c-abi.sh --check    # generate to a temp file; exit non-zero if
#                                   # it differs from the committed header
#
# Exit codes: 0 = success / no drift; 1 = drift detected or a tool error.

set -euo pipefail

ROOT="$(cd "$(dirname "$0")/.." && pwd)"
CONFIG="$ROOT/crates/vokra-capi/cbindgen.toml"
CRATE="vokra-capi"
HEADER="$ROOT/include/vokra.h"

# Prefer cbindgen on PATH, then the cargo bin dir (CI installs it with
# `cargo install cbindgen`; see the M0-09 CI job, T12).
if command -v cbindgen >/dev/null 2>&1; then
    CBINDGEN="cbindgen"
elif [ -x "${CARGO_HOME:-$HOME/.cargo}/bin/cbindgen" ]; then
    CBINDGEN="${CARGO_HOME:-$HOME/.cargo}/bin/cbindgen"
else
    echo "error: cbindgen not found. Install it with: cargo install cbindgen" >&2
    exit 1
fi

generate() {
    # $1 = output path. Run from ROOT so cbindgen resolves the crate manifest.
    ( cd "$ROOT" && "$CBINDGEN" --config "$CONFIG" --crate "$CRATE" --output "$1" --quiet )
}

case "${1:-}" in
    --check)
        tmp="$(mktemp -t vokra-h.XXXXXX)"
        trap 'rm -f "$tmp"' EXIT
        generate "$tmp"
        if [ ! -f "$HEADER" ]; then
            echo "error: $HEADER is missing; run scripts/gen-c-abi.sh to create it" >&2
            exit 1
        fi
        if diff -u "$HEADER" "$tmp"; then
            echo "gen-c-abi: OK (include/vokra.h is up to date)"
        else
            echo "error: include/vokra.h is out of date — run scripts/gen-c-abi.sh and commit" >&2
            exit 1
        fi
        ;;
    "")
        generate "$HEADER"
        echo "gen-c-abi: wrote $HEADER"
        ;;
    *)
        echo "usage: $0 [--check]" >&2
        exit 1
        ;;
esac
